import abc

# Ürün arayüzü
class Weapon(abc.ABC):
    @abc.abstractmethod
    def __str__(self):
        pass

# Somut Ürünler
class Sword(Weapon):
    def __str__(self):
        return "Kılıç"

class Bow(Weapon):
    def __str__(self):
        return "Yay"

# Yaratıcı soyut sınıfı
class Character(abc.ABC):
    def __init__(self):
        self._weapon = self._create_weapon()

    @abc.abstractmethod
    def _create_weapon(self) -> Weapon:
        pass

    def attack(self):
        return f"Karakter {self._weapon} ile saldırıyor!"

# Somut Yaratıcılar
class Warrior(Character):
    def _create_weapon(self) -> Weapon:
        return Sword()

class Archer(Character):
    def _create_weapon(self) -> Weapon:
        return Bow()

if __name__ == "__main__":
    warrior = Warrior()
    print(warrior.attack())

    archer = Archer()
    print(archer.attack())
